  /** Lấy chi tiết rate plan kèm phụ phí áp dụng theo quốc gia/thời gian */
  async getHotelRatePlanDetail(id: number, hotelId: number) {
    const priceSetting = await this.repo.getByHotelRatePlanDetail(id, hotelId);
    if (!priceSetting) throw new NotFoundError(ErrorCode.PRICE_SETTING_NOT_FOUND);

    const countriesIds = priceSetting.countries.map(c => c.id);
    const priceSettingPeriods = priceSetting.periods || [];

    const surchargeFeeSettings = await this.surchargeFeeSettingRepo.findByCountriesAndPeriodsOverlap(
      priceSetting.hotel.id,
      countriesIds,
      priceSettingPeriods,
    );

    return { priceSetting, surchargeFeeSettings };
  }

  /** Cập nhật một phần price setting và đồng bộ lại rate calendar */
  async partialUpdate(id: number, payload: UpdatePriceSettingInput) {
    const entity = await this.repo.findById(id, { relations: ['hotel', 'room', 'countries', 'season'] });
    if (!entity) throw new NotFoundError(ErrorCode.PRICE_SETTING_NOT_FOUND);
    const previousPeriods = this.clonePeriods(entity.periods);

    if (payload.seasonId) {
      const season = await this.seasonRepo.findById(payload.seasonId);
      if (!season) throw new NotFoundError(ErrorCode.SEASON_NOT_FOUND);
      entity.season = season;
      entity.periods = season.periods;
    } else if (payload.periods) {
      entity.periods = payload.periods;
      entity.season = null;
    }

    if (payload.countries) {
      const countries = await this.countryRepo.find({
        where: { id: In(payload.countries) },
      });
      if (!countries) throw new BusinessLogicError(ErrorCode.COUNTRY_NOT_FOUND);
      entity.countries = countries;
    }

    if (!isUndefined(payload.isActive)) entity.isActive = payload.isActive;
    if (payload.mealPlan) entity.mealPlan = payload.mealPlan;
    if (payload.price) entity.price = payload.price;
    if (payload.unitType) entity.unitType = payload.unitType;
    if (payload.amount) entity.amount = payload.amount;
    if (!isUndefined(payload.dayType)) entity.dayType = payload.dayType;
    if (payload.cancellationPeriod) entity.cancellationPeriod = payload.cancellationPeriod;
    if (payload.cancellationPeriodUnitTime) entity.cancellationPeriodUnitTime = payload.cancellationPeriodUnitTime;
    if (payload.condition) {
      if (payload.condition === CancellationType.NO_CANCELLATION) {
        entity.cancellationPeriod = null;
        entity.cancellationPeriodUnitTime = null;
        entity.unitType = null;
        entity.amount = 0;
      } else if (payload.condition === CancellationType.FREE_CANCELLATION) {
        if (entity.cancellationPeriod === 0 && !payload.cancellationPeriod) {
          throw new BusinessLogicError(ErrorCode.CANCELLATION_PERIOD_IS_REQUIRED);
        }
        if (payload.cancellationPeriod) entity.cancellationPeriod = payload.cancellationPeriod;
        if (payload.cancellationPeriodUnitTime) entity.cancellationPeriodUnitTime = payload.cancellationPeriodUnitTime;
        entity.unitType = null;
        entity.amount = 0;
      } else {
        if (
          (entity.cancellationPeriod === 0 && !payload.cancellationPeriod) ||
          (entity.amount === 0 && !payload.amount)
        ) {
          throw new BusinessLogicError(ErrorCode.CANCELLATION_PERIOD_IS_REQUIRED);
        }
        if (payload.cancellationPeriod) entity.cancellationPeriod = payload.cancellationPeriod;
        if (payload.cancellationPeriodUnitTime) entity.cancellationPeriodUnitTime = payload.cancellationPeriodUnitTime;
        if (payload.unitType) entity.unitType = payload.unitType;
        if (payload.amount) entity.amount = payload.amount;
      }
      entity.condition = payload.condition;
    }

    entity.updatedBy = payload.updatedBy;
    entity.name = this.getNameRatePlan(
      entity.condition,
      entity.mealPlan,
      entity.room?.localName,
      entity.amount,
      entity.unitType,
    );

    this.validatePeriodsFormat(entity.periods);
    const countryIds = entity.countries?.map(c => c.id).sort((a, b) => a - b) ?? [];
    await this.checkDuplicate(
      entity.hotel.id,
      entity.room.id,
      entity.mealPlan,
      countryIds,
      entity.dayType,
      entity.condition,
      entity.season?.id ?? null,
      entity.periods,
      id,
    );

    await this.repo.save(entity);
    await this.syncRateCalendar(entity, previousPeriods);
    return entity;
  }

  /** Tạo hàng loạt price setting (thường dùng khi sync hotel) */
  async insertMany(req: CreatePriceSettingInput[], hotel?: Hotel) {
    const items = [];
    for (const input of req) {
      const item = new PriceSetting();
      Object.assign(item, input);
      item.name = this.getNameRatePlan(
        input.condition,
        input.mealPlan,
        input.room.localName,
        input.amount,
        input.unitType,
      );
      if (hotel) item.hotel = hotel;
      items.push(item);
    }

    const savedItems = await this.repo.saveMany(items);
    await Promise.all(savedItems.map(item => this.syncRateCalendar(item)));
    return savedItems;
  }

  /** Xóa price setting và thu hồi các dòng rate calendar liên quan */
  async delete(id: number) {
    const entity = await this.repo.findById(id, { relations: ['hotel', 'room', 'season'] });
    if (!entity) throw new NotFoundError(ErrorCode.PRICE_SETTING_NOT_FOUND);
    const previousPeriods = this.clonePeriods(entity.periods);
    await this.repo.delete(id);
    entity.isActive = false;
    await this.syncRateCalendar(entity, previousPeriods);
  }
}

