  async findAllEventPaginated(params: SeasonQueryParamsInput): Promise<HttpPaginatedResponse<SeasonEvent>> {
    const { page, searchText, ownerId } = params;
    const size = 1e3;
    const skip = (page - 1) * size;

    const qb = this.seasonEventRepo.createQueryBuilder('entity');

    if (searchText) {
      qb.andWhere('entity.name ILIKE :search', { search: `%${searchText}%` });
    }

    if (ownerId) {
      qb.andWhere('(entity.ownerId = :ownerId OR entity.ownerId IS NULL)', { ownerId });
    }

    qb.orderBy(`entity.startMonth`, 'ASC').addOrderBy(`entity.startDay`, 'ASC');
    qb.skip(skip).take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<SeasonEvent>().withItems(items).withTotal(total).withPage(page).withSize(size);
