  async create(data: CreateSeasonInput) {
    const entity = new Season();
    Object.assign(entity, data);
    const hotel = await this.hotelRepo.findOne({
      where: { id: data.hotelId },
    });
    if (!hotel) throw new NotFoundError(ErrorCode.HOTEL_NOT_FOUND);
    entity.hotel = hotel;

    if (data.periods !== undefined) {
      entity.periods = data.periods;
      await this.validateSeasonDates(data.periods, data.type, hotel.id, entity.ownerId);
    }
    await this.assignSeasonDataByType(entity, data.type, data, true);
    return this.seasonRepo.save(entity);
  }

  async update(id: number, data: UpdateSeasonInput) {
    const entity = await this.findById(id);
    if (!entity) {
      return null;
    }

    if (data.name !== undefined) entity.name = data.name;
    if (data.periods !== undefined) {
      entity.periods = data.periods;
      await this.validateSeasonDates(data.periods, entity.type, entity.hotel.id, entity.ownerId, id);
    }
    if (data.description !== undefined) entity.description = data.description;
    if (data.isActive !== undefined) entity.isActive = data.isActive;

    if (data.type !== undefined) {
      entity.type = data.type;
      await this.assignSeasonDataByType(entity, data.type, data, false);
    } else {
      await this.updateSeasonDataByCurrentType(entity, data);
    }
    if (entity.type === SeasonType.DAY) {
      // check overlap day config
      const exist = await this.seasonRepo.findOne({
        where: {
          type: SeasonType.DAY,
          hotel: { id: entity.hotel.id },
          id: Not(id),
        },
      });
      if (exist && entity.day.dayOfWeek.some(day => exist.day.dayOfWeek.includes(day))) {
        throw new BusinessLogicError(ErrorCode.SEASON_DAY_DUPLICATE);
      }
    }
    await this.seasonRepo.save(entity);
    return this.findById(id);
  }

  async delete(id: number) {
    // check FK
    const entity = await this.seasonRepo.findOne({
      where: { id },
      relations: ['priceSettings', 'surchargeFeeSettings'],
    });
    if (!entity) throw new NotFoundError(ErrorCode.SEASON_NOT_FOUND);
    if (entity.priceSettings.length) throw new BasicError(ErrorCode.SEASON_WAS_USED);
    if (entity.surchargeFeeSettings.length) throw new BasicError(ErrorCode.SEASON_WAS_USED);
    return this.seasonRepo.delete(id);
  }

  findOne(options: FindOneOptions<Season>) {
    return this.seasonRepo.findOne(options);
  }

  async insertMany(req: CreateSeasonInput[], hotel?: Hotel) {
    const seasons = [];
    for (const rInput of req) {
      const season = new Season();
      Object.assign(season, rInput);
      if (hotel) season.hotel = hotel;
      seasons.push(season);
    }

    return this.seasonRepo.insertMany(seasons);
  }

  async defaultSeasonDay(hotel: Hotel) {
    const weekDay = {
      dayOfWeek: [0, 1, 2, 3, 4],
      name: DayType.WEEKDAY,
    };
    const weekEnd = {
      dayOfWeek: [5, 6],
      name: DayType.WEEKEND,
    };
    const seasons = [];
    for (const type of Object.values(DayType)) {
      const season = new Season();
      if (hotel) season.hotel = hotel;
      season.name = type;
      season.type = SeasonType.DAY;
      season.day = type === DayType.WEEKDAY ? weekDay : weekEnd;
      seasons.push(season);
    }

    return this.seasonRepo.insertMany(seasons);
  }
