import { Inject, Service } from 'typedi';
import { DataSource } from 'typeorm';

import { DayType } from '@Enums/Day';
import { CancellationType, MealPlan } from '@Enums/Hotel';
import { SortDirection } from '@Enums/SortDirection';

import { PriceSetting } from '@Entities/PriceSetting';

import { RangeDate } from '@DBCommon/RangeDate';

import { BaseOrmRepository } from '@Repositories/BaseOrmRepository';

import { PriceSettingQueryParamInput } from '@Services/types/PriceSettingInput';

@Service()
export class PriceSettingRepository extends BaseOrmRepository<PriceSetting> {
  constructor(@Inject('dataSource') dataSource: DataSource) {
    super(dataSource, PriceSetting);
  }

  async getById(id: number) {
    const queryBuilder = this.repo
      .createQueryBuilder('priceSetting')
      .leftJoin('priceSetting.room', 'room')
      .leftJoinAndSelect('priceSetting.season', 'season')
      .leftJoinAndSelect('priceSetting.countries', 'countries')
      .addSelect(['room.id', 'room.globalName', 'room.localName'])
      .where('priceSetting.id = :id', { id });

    return queryBuilder.getOne();
  }

  async getByHotelRatePlan(hotelId: number) {
    const qb = this.repo
      .createQueryBuilder('priceSetting')
      .leftJoinAndSelect('priceSetting.room', 'room')
      .leftJoin('priceSetting.hotel', 'hotel')
      .where('hotel.id = :hotelId', { hotelId })
      .andWhere('priceSetting.isActive = true');

    const [items, total] = await qb.getManyAndCount();
    return { items, total };
  }

  async getByHotelRatePlanDetail(id: number, hotelId: number) {
    const qb = this.repo
      .createQueryBuilder('priceSetting')
      .leftJoinAndSelect('priceSetting.countries', 'countries')
      .leftJoinAndSelect('priceSetting.room', 'room')
      .leftJoin('priceSetting.hotel', 'hotel')
      .addSelect(['hotel.id'])
      .where('priceSetting.id = :id', { id })
      .andWhere('hotel.id = :hotelId', { hotelId });

    return qb.getOne();
  }

  async findAll(query: PriceSettingQueryParamInput) {
    const {
      page = 1,
      size = 20,
      hotelId,
      ownerId,
      sortBy = 'createdAt',
      sortDirection = SortDirection.DESC,
      isActive,
    } = query;
    const skip = (page - 1) * size;

    const queryBuilder = this.repo
      .createQueryBuilder('priceSetting')
      .leftJoin('priceSetting.room', 'room')
      .leftJoinAndSelect('priceSetting.season', 'season')
      .leftJoinAndSelect('priceSetting.countries', 'countries')
      .addSelect(['room.id', 'room.globalName', 'room.localName']);

    if (isActive !== undefined) {
      queryBuilder.andWhere('priceSetting.isActive = :isActive', { isActive });
    }

    if (hotelId) {
      queryBuilder.andWhere('priceSetting.hotelId = :hotelId', { hotelId });
    }

    if (ownerId) {
      queryBuilder.andWhere('(priceSetting.ownerId = :ownerId OR priceSetting.ownerId IS NULL)', { ownerId });
    }

    const [items, total] = await queryBuilder
      .orderBy(`priceSetting.${sortBy}`, sortDirection)
      .skip(skip)
      .take(size)
      .getManyAndCount();

    return { items, total, page, size };
  }

  async findByHotelIds(hotelIds: number[]) {
    const qb = this.repo
      .createQueryBuilder('priceSetting')
      .leftJoin('priceSetting.hotel', 'hotel')
      .leftJoin('priceSetting.room', 'room')
      .where('hotel.id IN (:...hotelIds)', { hotelIds })
      .addSelect(['room.localName', 'room.id']);

    return qb.getMany();
  }

  async findByIds(ids: number[]) {
    const qb = this.repo
      .createQueryBuilder('priceSetting')
      .leftJoinAndSelect('priceSetting.hotel', 'hotel')
      .leftJoin('priceSetting.room', 'room')
      .where('priceSetting.id IN (:...ids)', { ids })
      .addSelect(['room.localName', 'room.id']);

    return qb.getMany();
  }

  /**
   * Check trùng lặp strict dựa trên:
   * - Loại phòng (room)
   * - Meal plan (mealPlan)
   * - Thị trường khách (countries)
   * - Loại ngày áp dụng (dayType)
   * - Điều kiện hoàn hủy (condition)
   *
   * Nếu các điều kiện trên trùng hoàn toàn thì check thời gian/mùa/sự kiện:
   * - Mùa trùng mùa (cùng seasonId)
   * - Mùa thông thường trùng thời gian tùy chỉnh (season có periods overlap với periods tùy chỉnh)
   * - Sự kiện trùng sự kiện (cùng eventId trong season) - KHÔNG trùng với thời gian tùy chỉnh
   * - Thời gian tùy chỉnh trùng thời gian tùy chỉnh (periods overlap)
   * - Thời gian tùy chỉnh trùng mùa thông thường (periods overlap với season.periods)
   */
  async findDuplicateStrict(
    hotelId: number,
    roomId: number,
    mealPlan: MealPlan,
    countryIds: number[],
    dayType: DayType | null,
    condition: CancellationType,
    seasonId: number | null,
    periods: RangeDate[],
    excludeId?: number,
  ) {
    const qb = this.repo.createQueryBuilder('ps').leftJoinAndSelect('ps.season', 'season');

    // Check các điều kiện bắt buộc
    qb.where('ps.hotelId = :hotelId', { hotelId })
      .andWhere('ps.roomId = :roomId', { roomId })
      .andWhere('ps.mealPlan = :mealPlan', { mealPlan })
      .andWhere('ps.dayType IS NOT DISTINCT FROM :dayType', {
        dayType: dayType ?? null,
      })
      .andWhere('ps.condition = :condition', { condition });

    // Exclude record hiện tại khi update
    if (excludeId) {
      qb.andWhere('ps.id != :excludeId', { excludeId });
    }

    // Check exact match cho countries (M2M relation)
    // Tối ưu: Dùng subquery với ARRAY_AGG thay vì JOIN
    qb.andWhere(
      `ARRAY(
        SELECT psc."geoCountryId"
        FROM price_setting_countries psc
        WHERE psc."priceSettingId" = ps.id
        ORDER BY psc."geoCountryId"
      ) = :countryIds::int[]`,
      { countryIds: countryIds.sort((a, b) => a - b) },
    );

    // Check mùa/sự kiện/thời gian tùy chỉnh
    if (seasonId) {
      // Trường hợp có season: check trùng với
      // 1. Các record cùng seasonId (bao gồm cả event trong season)
      // 2. NẾU là mùa thông thường (không phải event): Check các record thời gian tùy chỉnh overlap
      //    NẾU là mùa sự kiện: KHÔNG check với thời gian tùy chỉnh (event chỉ trùng event)
      qb.andWhere(
        `(
          ps.seasonId = :seasonId
          OR (
            ps.seasonId IS NULL
            AND EXISTS (
              SELECT 1
              FROM season input_season,
                   jsonb_array_elements(ps.periods) ps_period,
                   jsonb_array_elements(input_season.periods) input_season_period
              WHERE input_season.id = :seasonId
                AND input_season."eventId" IS NULL
                AND (ps_period->>'startDate')::timestamp < (input_season_period->>'endDate')::timestamp
                AND (ps_period->>'endDate')::timestamp > (input_season_period->>'startDate')::timestamp
            )
          )
        )`,
        { seasonId },
      );
    } else if (periods && periods.length > 0) {
      // Trường hợp thời gian tùy chỉnh
      // Check overlap với:
      // 1. Các record thời gian tùy chỉnh khác (seasonId IS NULL)
      // 2. Các record có mùa THÔNG THƯỜNG (không phải event) có periods overlap

      // Tối ưu: Gộp tất cả periods thành 1 điều kiện với VALUES để tránh lặp query
      qb.andWhere(
        `(
          (ps.seasonId IS NULL AND EXISTS (
            SELECT 1
            FROM jsonb_array_elements(ps.periods) ps_period,
                 (VALUES ${periods.map((_, i) => `(:startDate${i}, :endDate${i})`).join(', ')}) AS input_periods(start_date, end_date)
            WHERE (ps_period->>'startDate')::timestamp < input_periods.end_date::timestamp
              AND (ps_period->>'endDate')::timestamp > input_periods.start_date::timestamp
          ))
          OR (
            ps.seasonId IS NOT NULL
            AND season."eventId" IS NULL
            AND EXISTS (
              SELECT 1
              FROM jsonb_array_elements(season.periods) season_period,
                   (VALUES ${periods.map((_, i) => `(:startDate${i}, :endDate${i})`).join(', ')}) AS input_periods(start_date, end_date)
              WHERE (season_period->>'startDate')::timestamp < input_periods.end_date::timestamp
                AND (season_period->>'endDate')::timestamp > input_periods.start_date::timestamp
            )
          )
        )`,
      );

      periods.forEach((period, index) => {
        qb.setParameter(`startDate${index}`, period.startDate);
        qb.setParameter(`endDate${index}`, period.endDate);
      });
    }

    return qb.getOne();
  }
}

